                size++;
            }
        }

        const currentMax = MapB.get(xorSum) || 0;
        if (size > currentMax) {
            MapB.set(xorSum, size);
        }
    }

    // Step 3: Combine results
    let maxTotalSize = -1;

    for (const [xA, sA] of MapA.entries()) {
        // We need XB such that xA ^ XB = target, so XB = target ^ xA
